export const parseRawServerTextOptionValue = (value) => {
    if (typeof value !== 'string')
        return;
    return value;
};
export const normalizeServerTextOptionValue = (value, option) => value !== undefined && (option.limit === 0 || value.length <= option.limit) ? value : option.def;
export const serializeServerTextOptionValue = (value) => value;
export const toServerTextOption = (localize, query, option) => ({
    query,
    name: localize(option.name),
    description: option.description && localize(option.description),
    required: option.required,
    type: option.type,
    placeholder: localize(option.placeholder),
    def: option.def,
    limit: option.limit,
    shortcuts: option.shortcuts,
});
